+        */
+
+        /** \brief RRT-Connect (AOXRRTConnect) */
+        class AOXRRTConnect : public base::Planner
+        {
+        public:
+            /** \brief Constructor */
+            AOXRRTConnect(const base::SpaceInformationPtr &si, bool addIntermediateStates = false);
