+            if (segmentCount == fullSegmentCount)
+            { 
+                ++numCollisionCheckedEdges_;
+                parent->whitelistAsChild(child);
+                child->whitelistAsChild(parent);
+            }
+            return true;
+        }  
+    }  // namespace geometric
+}

