+                                     ->as<ompl::base::RealVectorStateSpace::StateType>(0)
+                                     ->values[0],
+                                 motion->state->as<ompl::base::HybridStateSpace::StateType>()
+                                     ->as<ompl::base::RealVectorStateSpace::StateType>(0)
+                                     ->values[1],
+                                 motion->state->as<ompl::base::HybridStateSpace::StateType>()
+                                     ->as<ompl::base::RealVectorStateSpace::StateType>(0)
+                                     ->values[2],
+                                 motion->state->as<ompl::base::HybridStateSpace::StateType>()
+                                     ->as<ompl::base::RealVectorStateSpace::StateType>(0)
+                                     ->values[3]};
+    if (x_cur[0] < 0.5 || x_cur[0] > 6 || x_cur[1] < 0 || x_cur[1] > 7)
+        return true;
+    return false;
