-            // As the sample is in the graph (and therefore could be part of g_t), prune iff g^(v) + h^(v) > g_t(x_g)
-            // g^(v) + h^(v) >= g_t(x_g)
-            return this->isCostWorseThan(lowerBoundHeuristicVertexFunc_(state), costThreshold_);
