+            if (edgeQueue_.empty() == false)
+            {
+                // Variable:
+                // The iterator to the vector of edges to the child:
+                VertexIdToEdgeQueueIterVectorUMap::const_iterator toIter;
+
+                // Get the vector of iterators
+                toIter = incomingEdges_.find(cVertex->getId());
