+            {
+                return rewireFactor_;
+            }
+
+            void setRewireFactor(double v)
+            {
+                if (v <= 1)
+                {
+                    OMPL_ERROR("%s: Rewire Factor needs to be greater than 1.", getName().c_str());
+                }
