+            public:
+
+                Motion() : accCost_(0), state_(NULL), control_(NULL), steps_(0), parent_(NULL), numChildren_(0), inactive_(false)
+                {
+                }
+
+                /** \brief Constructor that allocates memory for the state and the control */
+                Motion(const SpaceInformation *si) : accCost_(0), state_(si->allocState()), control_(si->allocControl()), steps_(0), parent_(NULL), numChildren_(0), inactive_(false)
+                {
+                }
+
+                virtual ~Motion()
+                {
+                }
+
+                virtual base::State* getState()
+                {
+                    return state_;
+                }
+                virtual Motion* getParent()
+                {
+                    return parent_;
+                }
+
+                base::Cost accCost_;
+
+                /** \brief The state contained by the motion */
+                base::State       *state_;
+
+                /** \brief The control contained by the motion */
+                Control           *control_;
+
+                /** \brief The number of steps_ the control is applied for */
+                unsigned int       steps_;
+
+                /** \brief The parent motion in the exploration tree */
+                Motion            *parent_;
+
+                /** \brief Number of children */
+                unsigned numChildren_;
+
+                /** \brief If inactive, this node is not considered for selection.*/
+                bool inactive_;
+
+
+            };
+
+            class Witness : public Motion
+            {
+            public:
+
+                Witness() : Motion(),rep_(NULL)
+                {
+                }
+
+                Witness(const SpaceInformation *si) : Motion(si), rep_(NULL)
+                {
+                }
+                virtual base::State* getState()
+                {
+                    return rep_->state_;
+                }
+                virtual Motion* getParent()
+                {
